import{_ as t,c as n,o as e,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"계획 검토: AI 계획을 시각적으로 검토하기 | Plannotator","description":"Plannotator 계획 검토 기능을 배워보세요. 시각적 인터페이스로 AI가 생성한 계획을 검토하고, 주석을 추가하여 승인하거나 거부하는 방법과 Approve와 Request Changes의 차이점을 알아봅니다.","frontmatter":{"title":"계획 검토: AI 계획을 시각적으로 검토하기 | Plannotator","subtitle":"계획 검토 기초: AI 계획을 시각적으로 검토하기","description":"Plannotator 계획 검토 기능을 배워보세요. 시각적 인터페이스로 AI가 생성한 계획을 검토하고, 주석을 추가하여 승인하거나 거부하는 방법과 Approve와 Request Changes의 차이점을 알아봅니다.","sidebarTitle":"5분 만에 계획 검토 배우기","tags":["계획 검토","시각적 검토","주석","승인","거부","Claude Code","OpenCode"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"ko/backnotprop/plannotator/platforms/plan-review-basics/index.md","filePath":"ko/backnotprop/plannotator/platforms/plan-review-basics/index.md"}'),o={name:"ko/backnotprop/plannotator/platforms/plan-review-basics/index.md"};function l(p,a,i,r,d,c){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="계획-검토-기초-ai-계획을-시각적으로-검토하기" tabindex="-1">계획 검토 기초: AI 계획을 시각적으로 검토하기 <a class="header-anchor" href="#계획-검토-기초-ai-계획을-시각적으로-검토하기" aria-label="Permalink to &quot;계획 검토 기초: AI 계획을 시각적으로 검토하기&quot;">​</a></h1><h2 id="이-강의를-마치면-할-수-있는-것" tabindex="-1">이 강의를 마치면 할 수 있는 것 <a class="header-anchor" href="#이-강의를-마치면-할-수-있는-것" aria-label="Permalink to &quot;이 강의를 마치면 할 수 있는 것&quot;">​</a></h2><ul><li>✅ Plannotator 시각적 인터페이스로 AI가 생성한 계획 검토하기</li><li>✅ 계획 텍스트를 선택하고 다양한 유형의 주석 추가하기 (삭제, 대체, 코멘트)</li><li>✅ 계획을 승인하여 AI가 구현을 계속하도록 하기</li><li>✅ 계획을 거부하고 주석을 피드백으로 AI에게 전송하기</li><li>✅ 주석 유형의 사용 시나리오와 차이점 이해하기</li></ul><h2 id="현재-겪고-있는-어려움" tabindex="-1">현재 겪고 있는 어려움 <a class="header-anchor" href="#현재-겪고-있는-어려움" aria-label="Permalink to &quot;현재 겪고 있는 어려움&quot;">​</a></h2><p><strong>문제 1</strong>: AI가 생성한 구현 계획을 터미널에서 읽으면 텍스트 양이 많고 구조가 불명확해서 검토하기 힘듭니다.</p><p><strong>문제 2</strong>: AI에게 피드백을 주고 싶을 때 &quot;3번째 단락 삭제&quot;, &quot;이 함수 수정&quot; 같은 텍스트 설명만 가능해서 소통 비용이 높고, AI가 잘못 이해할 수도 있습니다.</p><p><strong>문제 3</strong>: 계획 중 일부는 수정이 필요 없고, 일부는 대체가 필요하고, 일부는 코멘트가 필요한데, 이런 피드백을 구조화해주는 도구가 없습니다.</p><p><strong>문제 4</strong>: AI에게 계획을 승인했는지, 수정이 필요한지 어떻게 알려야 할지 모르겠습니다.</p><p><strong>Plannotator가 도와드립니다</strong>:</p><ul><li>터미널 대신 시각적 UI로 명확한 구조 제공</li><li>텍스트 선택만으로 주석 추가 가능 (삭제, 대체, 코멘트), 정확한 피드백</li><li>주석이 자동으로 구조화된 데이터로 변환되어 AI가 의도를 정확히 이해</li><li>원클릭 승인 또는 거부, AI가 즉시 응답</li></ul><h2 id="언제-이-기능을-사용하나요" tabindex="-1">언제 이 기능을 사용하나요 <a class="header-anchor" href="#언제-이-기능을-사용하나요" aria-label="Permalink to &quot;언제 이 기능을 사용하나요&quot;">​</a></h2><p><strong>사용 시나리오</strong>:</p><ul><li>AI Agent가 계획을 완료하고 <code>ExitPlanMode</code> 호출 시 (Claude Code)</li><li>AI Agent가 <code>submit_plan</code> 도구 호출 시 (OpenCode)</li><li>AI가 생성한 구현 계획을 검토해야 할 때</li><li>계획에 대한 수정 의견을 정확하게 피드백해야 할 때</li></ul><p><strong>적합하지 않은 시나리오</strong>:</p><ul><li>AI에게 직접 코드 구현을 시킬 때 (계획 검토 건너뛰기)</li><li>이미 계획을 승인했고, 실제 코드 변경을 검토해야 할 때 (코드 검토 기능 사용)</li></ul><h2 id="🎒-시작하기-전-준비사항" tabindex="-1">🎒 시작하기 전 준비사항 <a class="header-anchor" href="#🎒-시작하기-전-준비사항" aria-label="Permalink to &quot;🎒 시작하기 전 준비사항&quot;">​</a></h2><p><strong>사전 조건</strong>:</p><ul><li>✅ Plannotator CLI 설치 완료 (<a href="./../start/getting-started/">빠른 시작</a> 참조)</li><li>✅ Claude Code 또는 OpenCode 플러그인 설정 완료 (해당 설치 가이드 참조)</li><li>✅ AI Agent가 계획 검토 지원 (Claude Code 2.1.7+, 또는 OpenCode)</li></ul><p><strong>트리거 방식</strong>:</p><ul><li><strong>Claude Code</strong>: AI가 plan을 완료하면 자동으로 <code>ExitPlanMode</code> 호출, Plannotator 자동 시작</li><li><strong>OpenCode</strong>: AI가 <code>submit_plan</code> 도구 호출, Plannotator 자동 시작</li></ul><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><h3 id="계획-검토란-무엇인가" tabindex="-1">계획 검토란 무엇인가 <a class="header-anchor" href="#계획-검토란-무엇인가" aria-label="Permalink to &quot;계획 검토란 무엇인가&quot;">​</a></h3><p><strong>계획 검토</strong>는 Plannotator의 핵심 기능으로, AI가 생성한 구현 계획을 시각적으로 검토하는 데 사용됩니다.</p><div class="info custom-block"><p class="custom-block-title">왜 계획 검토가 필요한가요?</p><p>AI가 계획을 생성한 후 보통 &quot;이 계획 괜찮나요?&quot; 또는 &quot;구현을 시작할까요?&quot;라고 묻습니다. 시각적 도구가 없으면 터미널에서 순수 텍스트 계획을 읽고 &quot;좋아요&quot;, &quot;안 돼요, XX 수정해주세요&quot; 같은 모호한 피드백만 할 수 있습니다. Plannotator를 사용하면 시각적 인터페이스로 계획을 보고, 수정이 필요한 부분을 정확히 선택하여 구조화된 주석을 추가할 수 있어 AI가 의도를 더 쉽게 이해합니다.</p></div><h3 id="워크플로우" tabindex="-1">워크플로우 <a class="header-anchor" href="#워크플로우" aria-label="Permalink to &quot;워크플로우&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (계획 생성)    │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ ExitPlanMode / submit_plan</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│ Plannotator UI  │  ← 브라우저 자동 열림</span></span>
<span class="line"><span>│                 │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ 계획 내용   │  │</span></span>
<span class="line"><span>│ │ (Markdown) │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       │ 텍스트 선택</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ 주석 추가   │  │</span></span>
<span class="line"><span>│ │ Delete/    │  │</span></span>
<span class="line"><span>│ │ Replace/   │  │</span></span>
<span class="line"><span>│ │ Comment    │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ 결정      │  │</span></span>
<span class="line"><span>│ │ Approve/  │  │</span></span>
<span class="line"><span>│ │ Request   │  │</span></span>
<span class="line"><span>│ │ Changes   │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;allow&quot;} 또는</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (구현 계속)    │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h3 id="주석-유형" tabindex="-1">주석 유형 <a class="header-anchor" href="#주석-유형" aria-label="Permalink to &quot;주석 유형&quot;">​</a></h3><p>Plannotator는 네 가지 주석 유형을 지원하며, 각각 다른 용도가 있습니다:</p><table tabindex="0"><thead><tr><th>주석 유형</th><th>용도</th><th>AI가 받는 피드백</th></tr></thead><tbody><tr><td><strong>Delete</strong></td><td>불필요한 내용 삭제</td><td>&quot;삭제: [선택한 텍스트]&quot;</td></tr><tr><td><strong>Replace</strong></td><td>더 나은 내용으로 대체</td><td>&quot;대체: [선택한 텍스트]를 [입력한 텍스트]로&quot;</td></tr><tr><td><strong>Comment</strong></td><td>특정 내용에 코멘트, 수정 요구 없음</td><td>&quot;코멘트: [선택한 텍스트]. 설명: [입력한 코멘트]&quot;</td></tr><tr><td><strong>Global Comment</strong></td><td>전역 코멘트, 특정 텍스트와 연결 없음</td><td>&quot;전역 코멘트: [입력한 코멘트]&quot;</td></tr></tbody></table><h3 id="approve-vs-request-changes" tabindex="-1">Approve vs Request Changes <a class="header-anchor" href="#approve-vs-request-changes" aria-label="Permalink to &quot;Approve vs Request Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>결정 유형</th><th>동작</th><th>AI가 받는 피드백</th><th>적용 시나리오</th></tr></thead><tbody><tr><td><strong>Approve</strong></td><td>Approve 버튼 클릭</td><td><code>{&quot;behavior&quot;: &quot;allow&quot;}</code></td><td>계획에 문제 없음, 바로 승인</td></tr><tr><td><strong>Request Changes</strong></td><td>Request Changes 버튼 클릭</td><td><code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></td><td>수정이 필요한 부분 있음</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Claude Code와 OpenCode의 차이점</p><ul><li><strong>Claude Code</strong>: Approve 시 주석을 전송하지 않음 (주석 무시됨)</li><li><strong>OpenCode</strong>: Approve 시 주석을 메모로 전송 가능 (선택사항)</li></ul><p><strong>계획 거부 시</strong>: 어느 플랫폼이든 주석이 AI에게 전송됨</p></div><h2 id="따라하기" tabindex="-1">따라하기 <a class="header-anchor" href="#따라하기" aria-label="Permalink to &quot;따라하기&quot;">​</a></h2><h3 id="_1단계-계획-검토-트리거" tabindex="-1">1단계: 계획 검토 트리거 <a class="header-anchor" href="#_1단계-계획-검토-트리거" aria-label="Permalink to &quot;1단계: 계획 검토 트리거&quot;">​</a></h3><p><strong>Claude Code 예시</strong>:</p><p>Claude Code에서 AI와 대화하여 구현 계획을 생성하도록 합니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자: 사용자 인증 모듈 구현 계획을 작성해줘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: 네, 구현 계획입니다:</span></span>
<span class="line"><span>1. 사용자 모델 생성</span></span>
<span class="line"><span>2. 회원가입 API 구현</span></span>
<span class="line"><span>3. 로그인 API 구현</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(AI가 ExitPlanMode 호출)</span></span></code></pre></div><p><strong>OpenCode 예시</strong>:</p><p>OpenCode에서 AI는 자동으로 <code>submit_plan</code> 도구를 호출합니다.</p><p><strong>확인해야 할 것</strong>:</p><ol><li>브라우저가 자동으로 Plannotator UI를 엽니다</li><li>AI가 생성한 계획 내용이 표시됩니다 (Markdown 형식)</li><li>페이지 하단에 &quot;Approve&quot;와 &quot;Request Changes&quot; 버튼이 있습니다</li></ol><h3 id="_2단계-계획-내용-살펴보기" tabindex="-1">2단계: 계획 내용 살펴보기 <a class="header-anchor" href="#_2단계-계획-내용-살펴보기" aria-label="Permalink to &quot;2단계: 계획 내용 살펴보기&quot;">​</a></h3><p>브라우저에서 계획을 확인합니다:</p><ul><li>계획이 Markdown 형식으로 렌더링됩니다 (제목, 단락, 목록, 코드 블록 포함)</li><li>스크롤하여 전체 계획을 볼 수 있습니다</li><li>라이트/다크 모드 전환 지원 (오른쪽 상단의 테마 전환 버튼 클릭)</li></ul><h3 id="_3단계-계획-텍스트-선택하고-주석-추가하기" tabindex="-1">3단계: 계획 텍스트 선택하고 주석 추가하기 <a class="header-anchor" href="#_3단계-계획-텍스트-선택하고-주석-추가하기" aria-label="Permalink to &quot;3단계: 계획 텍스트 선택하고 주석 추가하기&quot;">​</a></h3><p><strong>Delete 주석 추가</strong>:</p><ol><li>마우스로 계획에서 삭제할 텍스트를 선택합니다</li><li>팝업 툴바에서 <strong>Delete</strong> 버튼을 클릭합니다</li><li>텍스트가 삭제 스타일로 표시됩니다 (빨간색 취소선)</li></ol><p><strong>Replace 주석 추가</strong>:</p><ol><li>마우스로 계획에서 대체할 텍스트를 선택합니다</li><li>팝업 툴바에서 <strong>Replace</strong> 버튼을 클릭합니다</li><li>팝업 입력창에 대체할 내용을 입력합니다</li><li>Enter를 누르거나 확인을 클릭합니다</li><li>원본 텍스트가 대체 스타일로 표시되고 (노란색 배경), 아래에 대체 내용이 표시됩니다</li></ol><p><strong>Comment 주석 추가</strong>:</p><ol><li>마우스로 계획에서 코멘트할 텍스트를 선택합니다</li><li>팝업 툴바에서 <strong>Comment</strong> 버튼을 클릭합니다</li><li>팝업 입력창에 코멘트 내용을 입력합니다</li><li>Enter를 누르거나 확인을 클릭합니다</li><li>텍스트가 코멘트 스타일로 표시되고 (파란색 하이라이트), 사이드바에 코멘트가 표시됩니다</li></ol><p><strong>Global Comment 추가</strong>:</p><ol><li>페이지 오른쪽 상단의 <strong>Add Global Comment</strong> 버튼을 클릭합니다</li><li>팝업 입력창에 전역 코멘트 내용을 입력합니다</li><li>Enter를 누르거나 확인을 클릭합니다</li><li>코멘트가 사이드바의 &quot;Global Comments&quot; 섹션에 표시됩니다</li></ol><p><strong>확인해야 할 것</strong>:</p><ul><li>텍스트 선택 후 툴바가 즉시 팝업됩니다 (Delete, Replace, Comment)</li><li>주석 추가 후 텍스트에 해당 스타일이 표시됩니다 (취소선, 배경색, 하이라이트)</li><li>사이드바에 모든 주석 목록이 표시되며, 클릭하면 해당 위치로 이동합니다</li><li>주석 옆의 <strong>삭제</strong> 버튼을 클릭하여 주석을 제거할 수 있습니다</li></ul><h3 id="_4단계-계획-승인하기" tabindex="-1">4단계: 계획 승인하기 <a class="header-anchor" href="#_4단계-계획-승인하기" aria-label="Permalink to &quot;4단계: 계획 승인하기&quot;">​</a></h3><p><strong>계획에 문제가 없다면</strong>:</p><p>페이지 하단의 <strong>Approve</strong> 버튼을 클릭합니다.</p><p><strong>확인해야 할 것</strong>:</p><ul><li>브라우저가 자동으로 닫힙니다 (1.5초 지연)</li><li>Claude Code/OpenCode 터미널에 계획 승인됨이 표시됩니다</li><li>AI가 계획 구현을 계속합니다</li></ul><div class="info custom-block"><p class="custom-block-title">Approve의 동작</p><ul><li><strong>Claude Code</strong>: <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>만 전송, 주석은 무시됨</li><li><strong>OpenCode</strong>: <code>{&quot;behavior&quot;: &quot;allow&quot;}</code> 전송, 주석을 메모로 전송 가능 (선택사항)</li></ul></div><h3 id="_5단계-계획-거부하기-request-changes" tabindex="-1">5단계: 계획 거부하기 (Request Changes) <a class="header-anchor" href="#_5단계-계획-거부하기-request-changes" aria-label="Permalink to &quot;5단계: 계획 거부하기 (Request Changes)&quot;">​</a></h3><p><strong>계획에 수정이 필요하다면</strong>:</p><ol><li>필요한 주석을 추가합니다 (Delete, Replace, Comment)</li><li>페이지 하단의 <strong>Request Changes</strong> 버튼을 클릭합니다</li><li>브라우저에 확인 대화상자가 표시됩니다</li></ol><p><strong>확인해야 할 것</strong>:</p><ul><li>확인 대화상자에 &quot;Send X annotations to AI?&quot;가 표시됩니다</li><li>확인을 클릭하면 브라우저가 자동으로 닫힙니다</li><li>Claude Code/OpenCode 터미널에 피드백 내용이 표시됩니다</li><li>AI가 피드백에 따라 계획을 수정합니다</li></ul><div class="tip custom-block"><p class="custom-block-title">Request Changes의 동작</p><ul><li><strong>Claude Code</strong>와 <strong>OpenCode</strong>: 모두 <code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code>를 전송합니다</li><li>주석이 구조화된 Markdown 텍스트로 변환됩니다</li><li>AI가 주석에 따라 계획을 수정하고 다시 ExitPlanMode/submit_plan을 호출합니다</li></ul></div><h3 id="_6단계-피드백-내용-확인하기-선택사항" tabindex="-1">6단계: 피드백 내용 확인하기 (선택사항) <a class="header-anchor" href="#_6단계-피드백-내용-확인하기-선택사항" aria-label="Permalink to &quot;6단계: 피드백 내용 확인하기 (선택사항)&quot;">​</a></h3><p>Plannotator가 AI에게 보낸 피드백 내용을 확인하려면 터미널에서 볼 수 있습니다:</p><p><strong>Claude Code</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan rejected by user</span></span>
<span class="line"><span>Please modify the plan based on the following feedback:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[구조화된 주석 내용]</span></span></code></pre></div><p><strong>OpenCode</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;feedback&gt;</span></span>
<span class="line"><span>[구조화된 주석 내용]</span></span>
<span class="line"><span>&lt;/feedback&gt;</span></span></code></pre></div><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><p>위 단계를 완료하면 다음을 할 수 있어야 합니다:</p><ul><li>[ ] AI가 계획 검토를 트리거하면 브라우저가 자동으로 Plannotator UI를 엽니다</li><li>[ ] 계획 텍스트를 선택하고 Delete, Replace, Comment 주석을 추가합니다</li><li>[ ] Global Comment를 추가합니다</li><li>[ ] 사이드바에서 모든 주석을 확인하고 해당 위치로 이동합니다</li><li>[ ] Approve를 클릭하면 브라우저가 닫히고 AI가 구현을 계속합니다</li><li>[ ] Request Changes를 클릭하면 브라우저가 닫히고 AI가 계획을 수정합니다</li></ul><p><strong>특정 단계가 실패하면</strong> 다음을 참조하세요:</p><ul><li><a href="./../../faq/common-problems/">자주 묻는 질문</a></li><li><a href="./../../start/installation-claude-code/">Claude Code 설치 가이드</a></li><li><a href="./../../start/installation-opencode/">OpenCode 설치 가이드</a></li></ul><h2 id="주의사항" tabindex="-1">주의사항 <a class="header-anchor" href="#주의사항" aria-label="Permalink to &quot;주의사항&quot;">​</a></h2><p><strong>흔한 오류 1</strong>: 텍스트 선택 후 툴바가 팝업되지 않음</p><p><strong>원인</strong>: 코드 블록 내의 텍스트를 선택했거나, 여러 요소에 걸쳐 텍스트를 선택했을 수 있습니다.</p><p><strong>해결방법</strong>:</p><ul><li>단일 단락이나 목록 항목 내의 텍스트를 선택하세요</li><li>코드 블록의 경우 Comment 주석을 사용하고, 여러 줄에 걸쳐 선택하지 마세요</li></ul><p><strong>흔한 오류 2</strong>: Replace 주석 추가 후 대체 내용이 표시되지 않음</p><p><strong>원인</strong>: 대체 내용 입력창이 제대로 제출되지 않았을 수 있습니다.</p><p><strong>해결방법</strong>:</p><ul><li>대체 내용 입력 후 Enter 키를 누르거나 확인 버튼을 클릭하세요</li><li>사이드바에 대체 내용이 표시되는지 확인하세요</li></ul><p><strong>흔한 오류 3</strong>: Approve 또는 Request Changes 클릭 후 브라우저가 닫히지 않음</p><p><strong>원인</strong>: 서버 오류 또는 네트워크 문제일 수 있습니다.</p><p><strong>해결방법</strong>:</p><ul><li>터미널에 오류 메시지가 있는지 확인하세요</li><li>브라우저를 수동으로 닫으세요</li><li>문제가 지속되면 <a href="./../../faq/troubleshooting/">문제 해결</a>을 참조하세요</li></ul><p><strong>흔한 오류 4</strong>: AI가 피드백을 받은 후 주석대로 수정하지 않음</p><p><strong>원인</strong>: AI가 주석의 의도를 제대로 이해하지 못했을 수 있습니다.</p><p><strong>해결방법</strong>:</p><ul><li>더 명확한 주석을 사용해보세요 (Replace가 Comment보다 더 명확함)</li><li>Comment를 사용하여 자세한 설명을 추가하세요</li><li>문제가 지속되면 계획을 다시 거부하고 주석 내용을 조정하세요</li></ul><p><strong>흔한 오류 5</strong>: 여러 Delete 주석 추가 후 AI가 일부 내용만 삭제함</p><p><strong>원인</strong>: 여러 Delete 주석 간에 중복이나 충돌이 있을 수 있습니다.</p><p><strong>해결방법</strong>:</p><ul><li>각 Delete 주석의 텍스트 범위가 중복되지 않도록 하세요</li><li>큰 단락을 삭제해야 한다면 전체 단락을 한 번에 선택하여 삭제하세요</li></ul><h2 id="이번-강의-요약" tabindex="-1">이번 강의 요약 <a class="header-anchor" href="#이번-강의-요약" aria-label="Permalink to &quot;이번 강의 요약&quot;">​</a></h2><p>계획 검토는 Plannotator의 핵심 기능으로, AI가 생성한 계획을 시각적으로 검토할 수 있게 해줍니다:</p><p><strong>핵심 동작</strong>:</p><ol><li><strong>트리거</strong>: AI가 <code>ExitPlanMode</code> 또는 <code>submit_plan</code> 호출, 브라우저가 자동으로 UI를 엽니다</li><li><strong>살펴보기</strong>: 시각적 인터페이스에서 계획 내용 확인 (Markdown 형식)</li><li><strong>주석</strong>: 텍스트 선택 후 Delete, Replace, Comment 또는 Global Comment 추가</li><li><strong>결정</strong>: Approve (승인) 또는 Request Changes (거부) 클릭</li><li><strong>피드백</strong>: 주석이 구조화된 데이터로 변환되어 AI가 피드백에 따라 계속하거나 계획 수정</li></ol><p><strong>주석 유형</strong>:</p><ul><li><strong>Delete</strong>: 불필요한 내용 삭제</li><li><strong>Replace</strong>: 더 나은 내용으로 대체</li><li><strong>Comment</strong>: 특정 내용에 코멘트, 수정 요구 없음</li><li><strong>Global Comment</strong>: 전역 코멘트, 특정 텍스트와 연결 없음</li></ul><p><strong>결정 유형</strong>:</p><ul><li><strong>Approve</strong>: 계획에 문제 없음, 바로 승인 (Claude Code는 주석 무시)</li><li><strong>Request Changes</strong>: 수정이 필요한 부분 있음, 주석이 AI에게 전송됨</li></ul><h2 id="다음-강의-예고" tabindex="-1">다음 강의 예고 <a class="header-anchor" href="#다음-강의-예고" aria-label="Permalink to &quot;다음 강의 예고&quot;">​</a></h2><blockquote><p>다음 강의에서는 **<a href="./../plan-review-annotations/">계획 주석 추가하기</a>**를 배웁니다.</p><p>배울 내용:</p><ul><li>Delete, Replace, Comment 주석을 정확하게 사용하는 방법</li><li>이미지 주석 추가하는 방법</li><li>주석 편집 및 삭제하는 방법</li><li>주석의 모범 사례와 일반적인 시나리오</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>소스 코드 위치 보기</strong></summary><blockquote><p>업데이트: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>라인</th></tr></thead><tbody><tr><td>계획 검토 UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>주석 유형 정의</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L1-L70" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>1-70</td></tr><tr><td>계획 검토 서버</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L91-L310" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>91-310</td></tr><tr><td>API: 계획 내용 가져오기</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L132-L134" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>132-134</td></tr><tr><td>API: 계획 승인</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L201-L277" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>201-277</td></tr><tr><td>API: 계획 거부</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L280-L309" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>280-309</td></tr><tr><td>Viewer 컴포넌트</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L1-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></td><td>1-100</td></tr><tr><td>AnnotationPanel 컴포넌트</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a></td><td>1-50</td></tr></tbody></table><p><strong>주요 타입</strong>:</p><ul><li><code>AnnotationType</code>: 주석 유형 열거형 (DELETION, INSERTION, REPLACEMENT, COMMENT, GLOBAL_COMMENT) (<code>packages/ui/types.ts:1-7</code>)</li><li><code>Annotation</code>: 주석 인터페이스 (<code>packages/ui/types.ts:11-33</code>)</li><li><code>Block</code>: 계획 블록 인터페이스 (<code>packages/ui/types.ts:35-44</code>)</li></ul><p><strong>주요 함수</strong>:</p><ul><li><code>startPlannotatorServer()</code>: 계획 검토 서버 시작 (<code>packages/server/index.ts:91</code>)</li><li><code>parseMarkdownToBlocks()</code>: Markdown을 Blocks로 파싱 (<code>packages/ui/utils/parser.ts</code>)</li></ul><p><strong>API 라우트</strong>:</p><ul><li><code>GET /api/plan</code>: 계획 내용 가져오기 (<code>packages/server/index.ts:132</code>)</li><li><code>POST /api/approve</code>: 계획 승인 (<code>packages/server/index.ts:201</code>)</li><li><code>POST /api/deny</code>: 계획 거부 (<code>packages/server/index.ts:280</code>)</li></ul><p><strong>비즈니스 규칙</strong>:</p><ul><li>Claude Code 승인 시 주석 전송 안 함 (<code>apps/hook/server/index.ts:132</code>)</li><li>OpenCode 승인 시 주석을 메모로 전송 가능 (<code>apps/opencode-plugin/index.ts:270</code>)</li><li>계획 거부 시 주석은 항상 전송됨 (<code>apps/hook/server/index.ts:154</code>)</li></ul></details>`,112)])])}const h=t(o,[["render",l]]);export{g as __pageData,h as default};
